VALUES
  ('locality-6f0ba476-moex-00205', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '丁公司飲料部門為該公司之最小現金產生單位，該部門淨資產之帳面金額為$760,000，其中 包含商譽$140,000。該飲料部門整體之公允價值為$600,000，商譽除外之可辨認淨資產公允價 值為$480,000，則其商譽價值減損損失為何？', '["$280,000", "$160,000", "$140,000", "$120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00206', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司在X3年初以$2,000,000取得機器，估計殘值$200,000，耐用年限8年，採用直線法提 列折舊與成本模式後續衡量。X5年底因製程改變，故複核其是否有價值減損之跡象。經評估 X5 年底該機器之可回收金額為$1,265,000。又 X7 年底該機器的使用方式發生重大變動，評 估其可回收金額為$950,000。假設機器之估計殘值與估計耐用年限均未改變，則X7年底應認 列多少減損損失迴轉利益？', '["$36,000", "$51,000", "$60,000", "$111,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00207', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '乙公司X6年7月1日購入一台機器，該機器定價$180,000，付款條件2/10，n/30，乙公司7月 12日支付價款。該機器購進當天，乙公司亦支付下列費用：運費$4,000、試車費$1,250、搬運途 中不慎損壞之修理費用$3,600、安裝費$2,250。該機器估計可用5年，殘值$3,900，使用年數合 計法提列折舊。X8年1月1日，該機器因進行重大修理，並支出$20,100，估計修理後尚可再使 用4年，無殘值。乙公司X10年9月1日以$25,000出售機器，其出售損益為何？', '["損失$4,680", "利益$4,680", "損失$5,000", "利益$5,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00208', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X1年底以$500,000（含交易成本）買入乙公司3年期的公司債，面額$500,000，票面 利率6%，每年12月31日付息。甲公司對該債券投資依照攤銷後成本來衡量。乙公司公司債 的預期信用損失估計金額如下表： 12個月預期信用損失 存續期間預期信用損失 X1年底 $5,000 $15,000 X2年底 $20,000 $35,000 X3年底 $55,000 $55,000 X1 年底，甲公司判斷所持有的乙公司之公司債自原始認列後信用風險未顯著增加。乙公司 X2 年發生財務困難，甲公司 X2 年底判斷乙公司債券之信用風險顯著增加，X3 年底該債券 已自活絡市場中消失，達到減損的狀態。甲公司在X2、X3年底各收到債券利息$30,000。甲 公司X4年底只收到利息與本金共計$482,000，其餘款項無法收回，甲公司在X4年應認列的 減損損失迴轉金額為何？', '["$0", "$10,300", "$18,000", "$37,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00209', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年12月31日，以每股$32購買乙公司20%普通股7,500股。乙公司之部分財務', '["X4年公司淨利為$85,000、每股發放現金股利$1.5及年底每股市價$28；", "X5年 公司淨利為$136,000、每股發放現金股利$2.5及年底每股市價$42。試問：甲公司將股票列入 採權益法之投資，相較於列入透過其他綜合損益按公允價值衡量之權益工具投資，對甲公司 X5年度損益之差額為何？", "($96,550)", "($77,800)"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00210', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X2年銷售一種附有2年保證維修期限之玩具兔，依據公司過去經驗得知有50%玩具 兔不會發生損壞，35%玩具兔會發生小瑕疵，15%玩具兔則會發生重大瑕疵。每隻玩具兔發生 小瑕疵和重大瑕疵時之平均修理費用分別為$150及$360。甲公司X2年度共銷售120隻玩具 兔，每隻售價為$1,950，X2年實際發生的免費維修支出$5,800。甲公司X2年12月31日帳 列估計產品保證負債餘額為何？', '["$5,800", "$6,980", "$12,780", "$18,580"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00211', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '乙公司X1年底部分帳戶餘額如下：應付帳款$28,500，長期抵押借款$80,000，估計產品保證 負債$15,000，遞延所得稅負債$18,500，短期借款$20,000，備抵呆帳貸餘$3,000，短期應付票 據$40,000，應付公司債$60,000（5年後到期），應收帳款明細帳貸餘$8,000，累計減損$8,000。 乙公司X1年底資產負債表應認列的流動負債金額為何？', '["$965,000", "$103,500", "$111,500", "$123,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00212', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於X2年初按股權淨值取得乙公司30%股權。甲公司X2年中將成本$80,000的商品以 $120,000出售給乙公司，該項商品至X2年底仍有1/2留在乙公司尚未出售。若乙公司X2年 度帳列淨利為$580,000，則甲公司X2年度應認列的投資收益為何？', '["$156,000", "$162,000", "$168,000", "$174,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00213', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲企業於X2年12月31日發行10年期的公司債券，面額$1,000,000，年利率6%，市場利率 5%，發行價格是$1,077,320。甲公司債每年發放一次債息，公司債溢折價以有效利息法攤銷。 試問：該公司債X4年應認列之利息費用為何？', '["$53,559.3", "$53,866", "$54,172.7", "$60,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00214', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X7年1月1日權益項目有普通股股本為$1,000,000（面額$10、流通在外股數100,000 股）、資本公積－普通股溢價$250,000及保留盈餘$850,000，每股面額$10。X7年3月1日以 每股$15購買庫藏股20,000股，同年5月1日以每股$12出售庫藏股11,500股，同年7月1 日註銷剩餘庫藏股票。經此些庫藏股交易後，對公司保留盈餘之影響數為何？', '["($77,000)", "($55,750)", "($34,500)", "$0"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
